INSERT INTO products (id, file, title_en, title_es, category_en, category_es, desc_en, desc_es, price) VALUES
(1, '20180125_170337.jpg', 'Classic Walnut Frame', 'Marco Nogal Clasico', 'Framing', 'Enmarcado', 'A timeless deep walnut frame custom-built for a family portrait.', 'Marco de nogal profundo hecho a medida, perfecto para retratos familiares.', 850),
(2, '20180202_164440.jpg', 'Rustic Oak Shadowbox', 'Caja de Sombras Roble', 'Framing', 'Enmarcado', 'Hand-finished rustic oak shadowbox designed to preserve memorabilia.', 'Caja de sombras de roble rustico acabada a mano para preservar recuerdos.', 1200),
(3, '20180205_165928.jpg', 'Modern Gallery Frame', 'Marco Galeria Moderno', 'Framing', 'Enmarcado', 'Sleek black gallery frame with museum-grade archival matting.', 'Marco de galeria negro con montaje de archivo de calidad museo.', 950),
(4, '20180208_184850.jpg', 'Ornate Gold Finish', 'Acabado Dorado Ornamentado', 'Maintenance', 'Restauracion', 'Restoration of an antique gold-leaf frame, bringing history back to life.', 'Restauracion de marco antiguo con hoja de oro, devolviendo la historia a la vida.', 1500),
(5, '20180208_184953.jpg', 'Minimalist Maple', 'Maple Minimalista', 'Framing', 'Enmarcado', 'Natural maple wood frame with a clear finish for a contemporary look.', 'Marco de madera de maple natural con acabado transparente contemporaneo.', 750),
(6, '20180215_185709.jpg', 'Vintage White Wash', 'Blanco Vintage', 'Framing', 'Enmarcado', 'Distressed white frame perfect for coastal or farmhouse decor.', 'Marco blanco desgastado perfecto para decoracion costera o campestre.', 680),
(7, '20180329_104214.jpg', 'Deep Canvas Floater', 'Flotador para Canvas', 'Mounting', 'Montaje', 'A custom floater frame that gives the illusion of the canvas floating inside.', 'Marco flotador personalizado que da la ilusion del canvas flotando.', 1100),
(8, '20180423_193653.jpg', 'Double Mat Presentation', 'Presentacion Doble Mat', 'Framing', 'Enmarcado', 'Elegant double matting in cream and navy to accent the artwork.', 'Elegante doble matting en crema y azul marino para acentuar la obra.', 900),
(9, '20180503_192206.jpg', 'Heirloom Restoration', 'Restauracion de Herencia', 'Maintenance', 'Restauracion', 'Detailed restoration work on a damaged mid-century frame.', 'Trabajo detallado de restauracion en un marco danado de mediados de siglo.', 1800),
(10, '20180507_183731.jpg', 'Corporate Certificate', 'Certificado Corporativo', 'Framing', 'Enmarcado', 'Professional framing for diplomas and corporate awards.', 'Enmarcado profesional para diplomas y premios corporativos.', 550),
(11, '20180509_151018.jpg', 'Artisan Corner Joinery', 'Union de Esquinas Artesanal', 'Framing', 'Enmarcado', 'Showcasing our precision corner joinery techniques.', 'Mostrando nuestras tecnicas de precision en union de esquinas.', 1050),
(12, '20180619_213821.jpg', 'Large Format Custom', 'Gran Formato Personalizado', 'Framing', 'Enmarcado', 'Oversized custom frame built reinforced for large-scale photography.', 'Marco personalizado reforzado para fotografia de gran escala.', 2200),
(13, '20180623_194708.jpg', 'Sports Jersey Display', 'Exhibidor de Jersey', 'Mounting', 'Montaje', 'Deep shadowbox with UV glass to protect a signed jersey.', 'Caja de sombras profunda con vidrio UV para proteger un jersey firmado.', 1600),
(14, '20180714_222234.jpg', 'Eclectic Mix', 'Mezcla Eclectica', 'Framing', 'Enmarcado', 'A unique combination of modern and traditional elements.', 'Una combinacion unica de elementos modernos y tradicionales.', 980),
(15, '20180819_145754.jpg', 'Fine Art Preservation', 'Preservacion de Arte Fino', 'Framing', 'Enmarcado', 'Conservation framing using acid-free materials to protect valuable art.', 'Enmarcado de conservacion con materiales libres de acido para arte valioso.', 1350),
(16, '20180831_193243.jpg', 'Texture & Depth', 'Textura y Profundidad', 'Framing', 'Enmarcado', 'Using a textured frame profile to add depth to a flat print.', 'Perfil de marco texturizado para agregar profundidad a una impresion plana.', 870),
(17, 'DSC_0022.JPG', 'Gallery Wall Collection', 'Coleccion Pared Galeria', 'Framing', 'Enmarcado', 'Part of a cohesive set designed for a client''s gallery wall.', 'Parte de un conjunto cohesivo para la pared de galeria de un cliente.', 920),
(18, 'DSC_0100.JPG', 'Detailed Wood Carving', 'Tallado en Madera Detallado', 'Framing', 'Enmarcado', 'Close-up of intricate wood carving details on a custom frame.', 'Detalles intricados de tallado en madera en un marco personalizado.', 1450),
(19, 'DSC_0871.JPG', 'Metallic Accent Frame', 'Marco Acento Metalico', 'Framing', 'Enmarcado', 'Brushed metal finish frame suitable for modern industrial interiors.', 'Marco con acabado de metal cepillado para interiores industriales modernos.', 1050),
(20, 'FB_IMG_1516136999466.jpg', 'Custom Mirror Framing', 'Enmarcado de Espejo', 'Framing', 'Enmarcado', 'Transforming a simple mirror into a statement piece.', 'Transforming a simple mirror into a statement piece.', 1150),
(21, 'IMG_20180208_185310_102.jpg', 'Hand-Stained Finish', 'Acabado Tenido a Mano', 'Framing', 'Enmarcado', 'Custom mixed stain to match the client''s existing furniture.', 'Tinte mezclado a medida para combinar con los muebles existentes del cliente.', 980),
(22, 'IMG-20180414-WA0023.jpg', 'Wedding Photo Series', 'Serie Foto de Boda', 'Framing', 'Enmarcado', 'Elegant and romantic framing for wedding photography.', 'Enmarcado elegante y romantico para fotografia de boda.', 1100),
(23, 'IMG-20180414-WA0024.jpg', 'Family Heritage', 'Herencia Familiar', 'Framing', 'Enmarcado', 'Preserving old family photographs with archival standards.', 'Preservando fotografias familiares antiguas con estandares de archivo.', 850),
(24, 'IMG-20180415-WA0020.jpg', 'Artist Showcase', 'Exhibicion de Artista', 'Framing', 'Enmarcado', 'Framing designed to let the art speak for itself.', 'Enmarcado disenado para dejar que el arte hable por si mismo.', 780),
(25, 'IMG-20180526-WA0038.jpg', 'Bold Color Choice', 'Color Audaz', 'Framing', 'Enmarcado', 'A vibrant frame color chosen to pop against a neutral wall.', 'Un color vibrante de marco elegido para resaltar contra una pared neutral.', 720),
(26, 'IMG-20180528-WA0014.jpg', 'Subtle Elegance', 'Elegancia Sutil', 'Framing', 'Enmarcado', 'Understated design that complements rather than competes.', 'Diseno discreto que complementa en lugar de competir.', 690),
(27, 'IMG-20180611-WA0045.jpg', 'Workshop Process', 'Proceso de Taller', 'Maintenance', 'Restauracion', 'Behind the scenes in our woodshop.', 'Detras de escenas en nuestro taller de madera.', 600),
(28, 'IMG-20180611-WA0046.jpg', 'Precision Cutting', 'Corte de Precision', 'Maintenance', 'Restauracion', 'Ensuring every angle is perfect for a seamless joint.', 'Asegurando que cada angulo sea perfecto para una union sin costuras.', 650),
(29, 'IMG-20180611-WA0047.jpg', 'Final Assembly', 'Ensamblaje Final', 'Maintenance', 'Restauracion', 'The final touches before the piece is ready for delivery.', 'Los toques finales antes de que la pieza este lista para entrega.', 700),
(30, 'IMG-20180908-WA0022.jpeg', 'Showcase Piece', 'Pieza de Exhibicion', 'Maintenance', 'Restauracion', 'The finished work ready to be displayed in the client''s home.', 'La obra terminada lista para exhibir en el hogar del cliente.', 950);
