INSERT INTO services (title_en, title_es, description_en, description_es, icon) VALUES
('Custom Framing', 'Enmarcado a Medida', 'Tailored frames designed to perfectly complement and protect your artwork, using premium hardwoods like Walnut, Oak, and Mahogany.', 'Marcos diseñados a medida para complementar y proteger perfectamente su obra de arte, utilizando maderas duras premium como Nogal, Roble y Caoba.', 'Ruler'),
('Large-Scale Frames', 'Marcos de Gran Escala', 'Specialized structural framing for oversized pieces, ensuring stability and visual impact without compromising elegance.', 'Enmarcado estructural especializado para piezas de gran tamano, asegurando estabilidad e impacto visual sin comprometer la elegancia.', 'Image'),
('Artistic Mounting', 'Montaje Artistico', 'Museum-quality mounting techniques that preserve the integrity of your pieces while enhancing their presentation.', 'Tecnicas de montaje de calidad de museo que preservan la integridad de sus piezas mientras mejoran su presentacion.', 'Palette');
