-- Migration: Initial schema for Galeria y Enmarcados del Bajio (Revised for Idempotency)

-- 1. Drop existing tables to ensure a clean update (CASCADE handles dependencies)
DROP TABLE IF EXISTS products CASCADE;
DROP TABLE IF EXISTS portfolio_items CASCADE;
DROP TABLE IF EXISTS moldings CASCADE;
DROP TABLE IF EXISTS mat_colors CASCADE;
DROP TABLE IF EXISTS mat_color_groups CASCADE;
DROP TABLE IF EXISTS services CASCADE;

-- 2. Create Tables
CREATE TABLE products (
  id BIGINT PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
  file TEXT NOT NULL,
  title_en TEXT NOT NULL,
  title_es TEXT NOT NULL,
  category_en TEXT NOT NULL,
  category_es TEXT NOT NULL,
  desc_en TEXT NOT NULL,
  desc_es TEXT NOT NULL,
  price FLOAT NOT NULL,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE portfolio_items (
  id BIGINT PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
  file TEXT NOT NULL,
  title_en TEXT NOT NULL,
  title_es TEXT NOT NULL,
  category_en TEXT NOT NULL,
  category_es TEXT NOT NULL,
  desc_en TEXT NOT NULL,
  desc_es TEXT NOT NULL,
  aspect TEXT NOT NULL,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE moldings (
  id BIGINT PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
  name_en TEXT NOT NULL,
  name_es TEXT NOT NULL,
  file TEXT NOT NULL,
  category_en TEXT NOT NULL,
  category_es TEXT NOT NULL,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE mat_color_groups (
  id BIGINT PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
  name_en TEXT NOT NULL,
  name_es TEXT NOT NULL,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE mat_colors (
  id BIGINT PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
  group_id BIGINT REFERENCES mat_color_groups(id) ON DELETE CASCADE,
  name_en TEXT NOT NULL,
  name_es TEXT NOT NULL,
  value TEXT NOT NULL,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE services (
  id BIGINT PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
  title_en TEXT NOT NULL,
  title_es TEXT NOT NULL,
  description_en TEXT NOT NULL,
  description_es TEXT NOT NULL,
  icon TEXT NOT NULL,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

